import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class XSSFixedCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize user input using OWASP ESAPI HTMLEntityCodec
        HTMLEntityCodec htmlEncoder = new HTMLEntityCodec();
        String sanitizedInput = htmlEncoder.encode(userInput);

        System.out.println("Sanitized User Input: " + sanitizedInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
